import java.util.Scanner;

public class SafeBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Implement proper security measures to prevent buffer overflow
        int maxLength = Math.min(name.length(), 10); // Limiting input length to 10 characters
        byte[] buffer = new byte[10];
        System.arraycopy(name.getBytes(), 0, buffer, 0, maxLength);

        System.out.println("Hello, " + new String(buffer, 0, maxLength));
    }
}

### Explanation:
